m = int(input())
n = int(input())

count = 0
numbers_divisible_by_6 = ""

for number in range(m, n + 1):

    if number % 6 == 0:
        count = count + 1
        numbers_divisible_by_6 = numbers_divisible_by_6 + str(number) + " "

if count == 0:
    print("No Numbers Found")
else:
    print(numbers_divisible_by_6)
